1	import { Chart, registerables } from 'chart.js';
2	import 'chartjs-adapter-date-fns';
3	import { createChart, LineSeries } from 'lightweight-charts';
4	import type { IChartApi } from 'lightweight-charts';
5	import { CHART_COLORS } from '../theme-constants';
6	import {
7	  DARK_CHART_OPTIONS,
8	  aggregateBmadCommands,
9	  classifyPromptType,
10	  classifyFileLayer,
11	  uniqueSessionCount,
12	  computeRollingAverage,
13	} from './ai-metrics-utils';
14	import type { CheckpointMeta } from './ai-metrics-utils';
15	
16	Chart.register(...registerables);
17	
18	// ── Chart instance registry ─────────────────────────────────────────────────
19	const chartjsRegistry = new Map<string, Chart>();
20	const lwcRegistry = new Map<string, IChartApi>();
21	
22	function destroyChartJs(id: string) {
23	  // Destroy from our registry first
24	  const c = chartjsRegistry.get(id);
25	  if (c) { c.destroy(); chartjsRegistry.delete(id); return; }
26	  // Also destroy any Chart.js instance created by initial SSR scripts
27	  const el = document.getElementById(id);
28	  if (el && el.tagName === 'CANVAS') {
29	    const existing = Chart.getChart(el as HTMLCanvasElement);
30	    if (existing) existing.destroy();
31	  }
32	}
33	
34	function destroyLwc(id: string) {
35	  const c = lwcRegistry.get(id);
36	  if (c) { c.remove(); lwcRegistry.delete(id); }
37	}
38	
39	// ── Helpers ─────────────────────────────────────────────────────────────────
40	const NO_DATA = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
41	
42	function ensureCanvas(id: string): HTMLCanvasElement | null {
43	  let el = document.getElementById(id);
44	  if (!el) return null;
45	  // If previously replaced with "No data" div, recreate canvas
46	  if (el.tagName !== 'CANVAS') {
47	    const parent = el.parentElement;
48	    if (!parent) return null;
49	    const canvas = document.createElement('canvas');
50	    canvas.id = id;
51	    parent.innerHTML = '';
52	    parent.appendChild(canvas);
53	    return canvas;
54	  }
55	  return el as HTMLCanvasElement;
56	}
57	
58	function ensureDiv(id: string): HTMLDivElement | null {
59	  const el = document.getElementById(id);
60	  if (!el) return null;
61	  // Clear previous lightweight-charts content
62	  el.innerHTML = '';
63	  return el as HTMLDivElement;
64	}
65	
66	function fmtLabel(c: CheckpointMeta): string {
67	  const d = new Date(c.commit_date);
68	  return `${d.getMonth()+1}/${d.getDate()} ${d.getHours()}:${String(d.getMinutes()).padStart(2,'0')}`;
69	}
70	
71	// ── Per-metric render functions ─────────────────────────────────────────────
72	
73	function renderMetric1(sorted: CheckpointMeta[]) {
74	  destroyLwc('metric-1');
75	  const container = ensureDiv('metric-1');
76	  if (!container) return;
77	  const series = sorted.map(c => ({
78	    time: Math.floor(new Date(c.commit_date).getTime() / 1000) as any,
79	    value: c.agent_percentage,
80	  }));
81	  if (!series.length) { container.innerHTML = NO_DATA; return; }
82	  const chart = createChart(container, {
83	    layout: { background: { color: 'transparent' }, textColor: CHART_COLORS.textColor },
84	    grid: { vertLines: { color: CHART_COLORS.gridLinesColor }, horzLines: { color: CHART_COLORS.gridLinesColor } },
85	    rightPriceScale: { borderVisible: false },
86	    timeScale: { borderVisible: false, timeVisible: false },
87	    handleScroll: false, handleScale: false, autoSize: true,
88	  });
89	  const s = chart.addSeries(LineSeries, { color: CHART_COLORS.lineColor, lineWidth: 2, pointMarkersVisible: true });
90	  const deduped = series.filter((p, i) => i === 0 || p.time !== series[i-1].time);
91	  s.setData(deduped);
92	  chart.timeScale().fitContent();
93	  lwcRegistry.set('metric-1', chart);
94	}
95	
96	function renderMetric2(checkpoints: CheckpointMeta[]) {
97	  const valEl = document.getElementById('stat-pure-ai-rate');
98	  const detailEl = document.getElementById('stat-pure-ai-detail');
99	  if (!valEl || !detailEl) return;
100	  const pureAiCount = checkpoints.filter(c => c.agent_percentage === 100).length;
101	  const rate = checkpoints.length > 0 ? Math.round((pureAiCount / checkpoints.length) * 100) : 0;
102	  valEl.textContent = `${rate}%`;
103	  detailEl.textContent = `${pureAiCount} of ${checkpoints.length} commits fully AI-authored`;
104	}
105	
106	function renderMetric3(sorted: CheckpointMeta[]) {
107	  destroyChartJs('metric-3');
108	  const canvas = ensureCanvas('metric-3');
109	  if (!canvas) return;
110	  const labels = sorted.map(fmtLabel);
111	  const values = sorted.map(c => Math.round((100 - c.agent_percentage) * 10) / 10);
112	  if (!values.length) { canvas.parentElement!.innerHTML = NO_DATA; return; }
113	  const ch = new Chart(canvas, {
114	    type: 'bar',
115	    data: { labels, datasets: [{ data: values, backgroundColor: '#f59e0b', borderRadius: 3 }] },
116	    options: { ...DARK_CHART_OPTIONS, plugins: { ...DARK_CHART_OPTIONS.plugins, tooltip: { ...DARK_CHART_OPTIONS.plugins.tooltip, callbacks: { label: ctx => ` ${ctx.parsed.y.toFixed(1)}%` } } } },
117	  });
118	  chartjsRegistry.set('metric-3', ch);
119	}
120	
121	function renderMetric4(sorted: CheckpointMeta[]) {
122	  destroyChartJs('metric-4');
123	  const canvas = ensureCanvas('metric-4');
124	  if (!canvas) return;
125	  const labels = sorted.map(fmtLabel);
126	  const datasets = [
