---
import type { CheckpointMeta } from '../lib/utils/ai-metrics-utils';

interface Props {
  checkpoints: CheckpointMeta[];
}
const { checkpoints } = Astro.props;

const sorted = [...checkpoints].sort(
  (a, b) => new Date(a.commit_date).getTime() - new Date(b.commit_date).getTime(),
);
const labels = sorted.map((c) => {
  const d = new Date(c.commit_date);
  return `${(d.getMonth()+1)}/${d.getDate()} ${d.getHours()}:${String(d.getMinutes()).padStart(2,'0')}`;
});

// Metric 6: stacked token breakdown
const m6Datasets = JSON.stringify([
  { label: 'Input', data: sorted.map((c) => c.tokens.input), backgroundColor: '#8b5cf6' },
  {
    label: 'Cache Creation',
    data: sorted.map((c) => c.tokens.cache_creation),
    backgroundColor: '#00f5ff',
  },
  {
    label: 'Cache Read',
    data: sorted.map((c) => c.tokens.cache_read),
    backgroundColor: '#22c55e',
  },
  { label: 'Output', data: sorted.map((c) => c.tokens.output), backgroundColor: '#f59e0b' },
]);

// Metric 7: cache leverage score time-series (lightweight-charts)
const m7Series = sorted.map((c) => {
  const total = c.tokens.input + c.tokens.cache_creation + c.tokens.cache_read + c.tokens.output;
  return {
    time: Math.floor(new Date(c.commit_date).getTime() / 1000),
    value: total > 0 ? Math.round((c.tokens.cache_read / total) * 1000) / 10 : 0,
  };
});

// Metric 8: API call count (sum of turn_count across sessions)
const m8Values = sorted.map((c) => c.turns.reduce((sum, t) => sum + t.turn_count, 0));

// Metric 9: model distribution doughnut
const modelMap = new Map<string, number>();
for (const cp of checkpoints) {
  for (const turn of cp.turns) {
    modelMap.set(turn.model, (modelMap.get(turn.model) ?? 0) + 1);
  }
}
const m9Labels = [...modelMap.keys()];
const m9Values = [...modelMap.values()];
const DOUGHNUT_COLORS = ['#8b5cf6', '#00f5ff', '#22c55e', '#f59e0b', '#ef4444', '#a0a0b0', '#e879f9', '#38bdf8', '#4ade80', '#fb923c'];
---

<!-- Section heading -->
<div class="col-span-full flex items-center gap-3 pt-2">
  <h2 class="font-label text-text-primary font-semibold text-base whitespace-nowrap">
    Token Economics
  </h2>
  <div class="flex-1 h-px bg-white/5"></div>
</div>

<!-- Metric 6: Token Breakdown (wide) -->
<div class="card-glass p-4 md:col-span-2">
  <h3 class="font-label text-text-primary font-medium text-sm mb-1">Token Breakdown per Checkpoint</h3>
  <p class="font-label text-text-muted text-xs mb-1">
    Stacked view of input, cache creation, cache read, and output tokens per checkpoint.
  </p>
  <p class="font-label text-text-muted text-xs mb-3">
    Source: tokens.input, tokens.cache_creation, tokens.cache_read, tokens.output
  </p>
  <div style="position:relative; height:220px">
    <canvas
      id="metric-6"
      data-labels={JSON.stringify(labels)}
      data-datasets={m6Datasets}
    ></canvas>
  </div>
</div>

<!-- Metric 7: Cache Leverage Score (wide) -->
<div class="card-glass p-4 md:col-span-2">
  <h3 class="font-label text-text-primary font-medium text-sm mb-1">Cache Leverage Score</h3>
  <p class="font-label text-text-muted text-xs mb-1">
    Ratio of cache-read tokens to total tokens per checkpoint over time.
  </p>
  <p class="font-label text-text-muted text-xs mb-3">
    Source: tokens.cache_read, total_tokens, commit_date
  </p>
  <div
    id="metric-7"
    style="height:200px"
    data-series={JSON.stringify(m7Series)}
  >
  </div>
</div>

<!-- Metric 8: API Call Count -->
<div class="card-glass p-4">
  <h3 class="font-label text-text-primary font-medium text-sm mb-1">API Call Count</h3>
  <p class="font-label text-text-muted text-xs mb-1">
    Number of turns (API calls) made per checkpoint.
  </p>
  <p class="font-label text-text-muted text-xs mb-3">Source: turns.length</p>
  <div style="position:relative; height:180px">
    <canvas
      id="metric-8"
      data-labels={JSON.stringify(labels)}
      data-values={JSON.stringify(m8Values)}
    ></canvas>
  </div>
</div>

<!-- Metric 9: Model Distribution -->
<div class="card-glass p-4">
  <h3 class="font-label text-text-primary font-medium text-sm mb-1">Model Distribution</h3>
  <p class="font-label text-text-muted text-xs mb-1">
    Frequency of each model used across all turns in all checkpoints.
  </p>
  <p class="font-label text-text-muted text-xs mb-3">Source: turns[].model</p>
  <div style="position:relative; height:200px">
    <canvas
      id="metric-9"
      data-labels={JSON.stringify(m9Labels)}
      data-values={JSON.stringify(m9Values)}
      data-colors={JSON.stringify(m9Labels.map((_, i) => DOUGHNUT_COLORS[i % DOUGHNUT_COLORS.length]))}
    ></canvas>
  </div>
</div>

<script>
  import { createChart, LineSeries } from 'lightweight-charts';
  import { Chart, registerables } from 'chart.js';
  import { CHART_COLORS } from '../lib/theme-constants';
  import { DARK_CHART_OPTIONS } from '../lib/utils/ai-metrics-utils';

  Chart.register(...registerables);

  // Metric 6 — stacked bar
  const m6Canvas = document.getElementById('metric-6') as HTMLCanvasElement | null;
  if (m6Canvas) {
    const labels: string[] = JSON.parse(m6Canvas.dataset.labels ?? '[]');
    const datasets: Array<{ label: string; data: number[]; backgroundColor: string }> = JSON.parse(
      m6Canvas.dataset.datasets ?? '[]',
    );
    if (!labels.length) {
      const p6 = m6Canvas.parentElement;
      if (p6) p6.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m6Canvas, {
        type: 'bar',
        data: { labels, datasets: datasets.map((ds) => ({ ...ds, borderRadius: 2 })) },
        options: {
          ...DARK_CHART_OPTIONS,
          plugins: {
            ...DARK_CHART_OPTIONS.plugins,
            legend: { display: true, labels: { color: '#a0a0b0', font: { family: 'Inter' } } },
          },
          scales: {
            ...DARK_CHART_OPTIONS.scales,
            x: { ...DARK_CHART_OPTIONS.scales.x, stacked: true },
            y: { ...DARK_CHART_OPTIONS.scales.y, stacked: true },
          },
        },
      });
    }
  }

  // Metric 7 — lightweight-charts line (cache leverage)
  const m7Container = document.getElementById('metric-7') as HTMLDivElement | null;
  if (m7Container) {
    const rawSeries: Array<{ time: number; value: number }> = JSON.parse(
      m7Container.dataset.series ?? '[]',
    );
    if (!rawSeries.length) {
      m7Container.innerHTML =
        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      const chart = createChart(m7Container, {
        layout: { background: { color: 'transparent' }, textColor: CHART_COLORS.textColor },
        grid: {
          vertLines: { color: CHART_COLORS.gridLinesColor },
          horzLines: { color: CHART_COLORS.gridLinesColor },
        },
        rightPriceScale: { borderVisible: false },
        timeScale: { borderVisible: false, timeVisible: false },
        handleScroll: false,
        handleScale: false,
        autoSize: true,
      });
      const series = chart.addSeries(LineSeries, {
        color: '#22c55e',
        lineWidth: 2,
        pointMarkersVisible: true,
      });
      const deduped7 = rawSeries.filter((p, i) => i === 0 || p.time !== rawSeries[i - 1].time);
      series.setData(deduped7);
      chart.timeScale().fitContent();
    }
  }

  // Metric 8 — bar chart
  const m8Canvas = document.getElementById('metric-8') as HTMLCanvasElement | null;
  if (m8Canvas) {
    const labels: string[] = JSON.parse(m8Canvas.dataset.labels ?? '[]');
    const values: number[] = JSON.parse(m8Canvas.dataset.values ?? '[]');
    if (!values.length) {
      const p8 = m8Canvas.parentElement;
      if (p8) p8.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m8Canvas, {
        type: 'bar',
        data: {
          labels,
          datasets: [{ data: values, backgroundColor: '#8b5cf6', borderRadius: 3 }],
        },
        options: DARK_CHART_OPTIONS,
      });
    }
  }

  // Metric 9 — doughnut
  const m9Canvas = document.getElementById('metric-9') as HTMLCanvasElement | null;
  if (m9Canvas) {
    const labels: string[] = JSON.parse(m9Canvas.dataset.labels ?? '[]');
    const values: number[] = JSON.parse(m9Canvas.dataset.values ?? '[]');
    const colors: string[] = JSON.parse(m9Canvas.dataset.colors ?? '[]');
    const hasRealLabels = labels.some((l) => l.trim() !== '');
    if (!values.length || !hasRealLabels) {
      const p9 = m9Canvas.parentElement;
      if (p9) p9.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m9Canvas, {
        type: 'doughnut',
        data: { labels, datasets: [{ data: values, backgroundColor: colors, borderWidth: 0 }] },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: { display: true, position: 'bottom', labels: { color: '#a0a0b0', font: { family: 'Inter', size: 10 }, boxWidth: 12, padding: 8 } },
            tooltip: DARK_CHART_OPTIONS.plugins.tooltip,
          },
        },
      });
    }
  }
</script>

