---
import type { CheckpointMeta } from '../lib/utils/ai-metrics-utils';

interface Props {
  checkpoints: CheckpointMeta[];
}
const { checkpoints } = Astro.props;

const sorted = [...checkpoints].sort(
  (a, b) => new Date(a.commit_date).getTime() - new Date(b.commit_date).getTime(),
);
const labels = sorted.map((c) => {
  const d = new Date(c.commit_date);
  return `${(d.getMonth()+1)}/${d.getDate()} ${d.getHours()}:${String(d.getMinutes()).padStart(2,'0')}`;
});

// Metric 1: agent_percentage time-series (lightweight-charts)
const m1Series = sorted.map((c) => ({
  time: Math.floor(new Date(c.commit_date).getTime() / 1000),
  value: c.agent_percentage,
}));

// Metric 2: pure-AI commit rate stat card
const pureAiCount = checkpoints.filter((c) => c.agent_percentage === 100).length;
const pureAiRate =
  checkpoints.length > 0 ? Math.round((pureAiCount / checkpoints.length) * 100) : 0;

// Metric 3: human edit rate bar chart (human % per checkpoint)
const m3Values = sorted.map((c) => {
  return Math.round((100 - c.agent_percentage) * 10) / 10;
});

// Metric 4: stacked percentage bar — agent% vs human% per checkpoint
// NOTE: agent_lines/human_added are repo-wide snapshots, NOT per-checkpoint deltas.
// We use agent_percentage directly which IS meaningful per checkpoint.
const m4Datasets = JSON.stringify([
  { label: 'Agent %', data: sorted.map((c) => Math.round(c.agent_percentage * 10) / 10), backgroundColor: '#8b5cf6' },
  { label: 'Human %', data: sorted.map((c) => Math.round((100 - c.agent_percentage) * 10) / 10), backgroundColor: '#22c55e' },
]);

// Metric 5: average agent percentage across checkpoints
const m5Value = checkpoints.length > 0
  ? Math.round(checkpoints.reduce((sum, c) => sum + c.agent_percentage, 0) / checkpoints.length * 10) / 10
  : 0;
---

<!-- Section heading -->
