import { getCheckpointSource } from '../lib/utils/github-checkpoints';

const cachePath = resolve('./src/data/checkpoints-cache.json');
let cache: CheckpointsCache | null = null;
if (existsSync(cachePath)) {
  try {
    cache = JSON.parse(readFileSync(cachePath, 'utf-8')) as CheckpointsCache;
  } catch {
    // malformed or corrupt cache — treat as missing
  }
}

const checkpoints = filterRenderableCheckpoints(cache?.checkpoints ?? []);
const source = getCheckpointSource();
---

<AiMetricsLayout>
  <AiMetricsDashboard
    client:load
    initialCheckpoints={checkpoints}
    meta={cache?.meta ?? null}
    source={source}
  />
</AiMetricsLayout>

